import React, { FunctionComponent, memo } from 'react';
import { useTranslation } from 'react-i18next';

import SitePage from '../SitePage/SitePage';
import CategoryHeader from './CategoryHeader/CategoryHeader';
import { ArticlePreview as ArticlePreviewType } from '../../models/Blog';
import ArticlePreview from './ArticlePreview/ArticlePreview';
import { ArticlesContextConsumer } from '../../context/ArticlesContext'
import './CategoryPage.scss';

interface CategoryProps {}

const CategoryPage: FunctionComponent<CategoryProps> = () => {
  const { t } = useTranslation('Category');

  return (
    <ArticlesContextConsumer>
        {({ currentCategory, currentArticlesPreview }) => currentCategory ? (
          <SitePage className={`CategoryPage ${currentCategory}`}>
            <section className="CategoryPage-header section-inner">
              <CategoryHeader category={currentCategory} categoryValue={1} />
              <div className="CategoryPage-image" />
            </section>
            <section className="CategoryPage-articles section-outer">
              <section className="section-inner">
                <h3 className="CategoryPage-articles-teaser">
                  {t(`${currentCategory}.articles.teaser`)}
                  <span className="CategoryPage-articles-teaser-cnt">{currentArticlesPreview?.length}</span>
                </h3>
                {currentArticlesPreview?.map((article: ArticlePreviewType) => (
                  <ArticlePreview key={article.slug} category={currentCategory} article={article} />
                ))}
              </section>
            </section>
        </SitePage>) : <></>}
      </ArticlesContextConsumer>
  );
}

export default memo(CategoryPage);
