import React, { FunctionComponent, memo } from 'react';
import { Trans, useTranslation } from 'react-i18next';
import { Link } from 'react-router-dom';

import Category from '../../../models/Category';
import Page from '../../../models/Page';
import CategoryTitle from '../../CategoryTitle/CategoryTitle';
import CircleContainer from '../../CircleContainer/CircleContainer';
import ChevronIcon from '../../SVGs/ChevronIcon';
import variables from '../../../assets/styles/variables.module.scss';
import './CategoryHeader.scss';

interface CategoryHeaderProps {
  category: Category;
  categoryValue: number;
}

const CategoryHeader: FunctionComponent<CategoryHeaderProps> = ({ category, categoryValue }) => {
    const { t } = useTranslation('Category');
    return (<div className="CategoryHeader">
        <CategoryTitle category={category} className="CategoryHeader-icon" />
        <Trans
        ns="Category"
        parent="h2"
        className="CategoryHeader-title"
        i18nKey={`${category}.teaser`}
        components={{ span: <span className="has-font-secondary" /> }}
        />
        <div className="CategoryHeader-description">
        <Trans
            ns="Category"
            parent="p"
            i18nKey={`${category}.description`}
            components={{ span: <span className="is-underlined" /> }}
        />
        <Link to={`/${t(Page.METHODOLOGY, {ns: 'Page'})}/#${t(`${category}.methodologyAnchor`)}`} className="CategoryHeader-description-link">
            <span className="chevron">
            <ChevronIcon color={variables.primaryInvert} />
            </span>
            <span>{t(`${category}.more`)}</span>
        </Link>
        </div>
        <CircleContainer className="CategoryHeader-circle">
        <span className="CategoryHeader-circle-title">
            {categoryValue > 0 ? t(`${category}.optimist`) : t(`${category}.pessimist`)}
        </span>
        <div className="CategoryHeader-circle-value">
            <span className="CategoryHeader-circle-value-indicator">
            {categoryValue > 0 ? '▲' : '▼'}
            </span>
            {' '}
            {categoryValue}
            %
        </div>
        <Link to={`/${t(Page.METHODOLOGY, {ns: 'Page'})}/#${t(`${category}.methodologyAnchor`)}`} className="chevron">
            <ChevronIcon />
        </Link>
        </CircleContainer>
        </div>);
}

export default memo(CategoryHeader)